{
  "metadata": {
    "name":        "LearnHelloWorld",            // PascalCase; becomes the class name
    "displayName": "Hello World",                  // human-readable title
    "description": "The five-minute first-screen tutorial.",
    "platforms":   ["web"],                        // drives jui build's distribution
    "layoutFile":  "learn/hello-world",            // → docs/screens/layouts/learn/hello-world.json
    "parentSpec":  "../home.spec.json",             // optional — for screen_sub_spec
    "createdAt":   "2026-04-22",
    "updatedAt":   "2026-04-24"
  }
}

{
  "stateManagement": {
    "states":        [],                                 // rarely used; persistent state machines
    "uiVariables": [                                     // everything the Layout binds to
      { "name": "count",            "type": "Int",    "initial": "0" },
      { "name": "statusVisibility", "type": "String", "initial": "\"gone\"" }
    ],
    "eventHandlers": [                                   // every handler the Layout binds onClick to
      { "name": "onIncrement", "description": "Bump count; flip statusVisibility." }
    ],
    "displayLogic":  [                                   // derive visibility / enabled from state
      {
        "condition": "count > 0",
        "effects":   [{ "element": "status_label", "state": "visible",
                        "variableName": "statusVisibility" }]
      }
    ]
  }
}

{
  "dataFlow": {
    "diagram": "flowchart TD\n    VIEW --> VM\n    VM -- rows --> VIEW",
    "viewModel": {                                       // the public VM contract
      "methods": [
        { "name": "onAppear",       "description": "Seed rows." },
        { "name": "onSelect", "params": [{ "name": "id", "type": "String" }] }
      ],
      "vars": [
        { "name": "rows", "type": "Array(ActivityRow)", "observable": true }
      ]
    },
    "customTypes": [                                     // reusable shapes (see Pattern 4)
      {
        "name":        "ActivityRow",
        "properties": [
          { "name": "id",    "type": "String" },
          { "name": "title", "type": "String" }
        ]
      }
    ],
    "repositories": [], "useCases": [], "apiEndpoints": []   // architecture-level slots
  }
}

{
  // Most screens leave `structure` mostly empty and let layout_importer
  // inline the tree from metadata.layoutFile at generate time.
  "structure": {
    "components":         [],      // auto-imported from the Layout JSON
    "layout":             {},      // same — flat tree of the Layout hierarchy
    "collection":         null,    // only set when the screen is a single-Collection page
    "tabView":            null,    // only set when the screen is a root TabView
    "decorativeElements": [],      // purely presentational children
    "wrapperViews":       [],      // structural wrappers with a purpose note
    "customComponents":   [        // see Pattern 3 (component_spec)
      { "name": "CodeBlock",
        "ref":  "docs/components/json/codeblock.component.json" }
    ]
  }
}
